106→function seedStore(points: number) {
107→  const state = useRootStore.getState() as Record<string, any>;
108→  if (state.pointsExtractActions) {
109→    state.pointsExtractActions.setBalance(points);
110→  }
111→}
112→
113→function LearnMoreSection({ isLoading }: { isLoading: boolean }) {
114→  if (isLoading) {
115→    return (
116→      <Box>
117→        <Text type="paragraphXXXL" mb="xxxs">
118→          Saiba mais
119→        </Text>
120→        {[1, 2, 3, 4].map(i => (
121→          <Skeleton key={i} width="100%" height={72} mb="xxs" />
122→        ))}
123→      </Box>
124→    );
125→  }
126→
127→  return (
128→    <Box>
129→      <Text type="paragraphXXXL" mb="xxxs">
130→        Saiba mais
131→      </Text>
132→      {MOCK_LEARN_MORE_DATA.map(item => (
133→        <CardActivity
134→          key={item.category}
135→          title={item.category}
136→          titleTextType={'paragraphMD' as PropsCardActivity['titleTextType']}
137→          mt="nano"
138→          icon={item.icon}
139→          onPress={() => {}}
140→          showIcon
141→          showIconRight
142→          descriptionColor="INTENSE_COLOR_05"
143→          iconRight="icon-next"
144→          showButton={false}
145→          showTagLabel={false}
146→        />
147→      ))}
148→    </Box>
149→  );
150→}
151→
152→function ErrorState({ onRetry }: { onRetry: () => void }) {
153→  return (
154→    <Box flex={1} justify="center" align="center" pd="innerLarge">
155→      <Icon name="icon-circle-alert" color="DENY_COLOR_01" size={48} />
156→      <Text type="paragraphXXXL" align="center" mt="smaller" mb="xxxs">
157→        Ops, algo deu errado...
158→      </Text>
159→      <Text type="paragraphMD" align="center" color="INTENSE_COLOR_05" mb="smaller">
160→        Por favor, tente novamente.
161→      </Text>
162→    </Box>
163→  );
164→}
165→
166→function PointsStoryWrapper({
167→  points = 15320,
168→  isLoading = false,
169→  hasError = false,
170→}: {
171→  points?: number;
172→  isLoading?: boolean;
173→  hasError?: boolean;
174→}) {
175→  const [isMyOrders, setIsMyOrders] = useState(false);
176→
177→  useEffect(() => {
178→    seedStore(points);
179→  }, [points]);
180→
181→  return (
182→    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
183→      <Header
184→        title={isMyOrders ? 'Meu espaço' : 'Programa de Pontos'}
185→        iconLeft="icon-back"
186→        hideLeftIcon={false}
187→        onBack={() => {
188→          if (isMyOrders) {
189→            setIsMyOrders(false);
190→          }
191→        }}
192→        isOption={!isMyOrders}
193→        iconRight="icon-menu"
194→        onPressIconRight={() => setIsMyOrders(true)}
195→      />
196→      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
197→        {hasError ? (
198→          <ErrorState onRetry={() => {}} />
199→        ) : isMyOrders ? (
200→          <CardActivity
201→            isLoading={isLoading}
202→            icon="icon-shopping-bag"
203→            showIcon
204→            showIconRight={false}
205→            hideBackground
206→            hideBorder
207→            title="Meus pedidos"
208→            titleTextType="paragraphXL"
209→            onPress={() => {}}
210→          />
211→        ) : (
212→          <Box ml="smaller" mr="smaller">
213→            <CardPoints
214→              icon="icon-benefits"
215→              iconInfo="icon-help"
216→              iconAction="icon-next"
217→              isLoading={isLoading}
218→              mt="smaller"
219→              mb="xs"
220→              onPressIconInfo={() => {}}
221→              onPressExtract={() => {}}
222→              textExtract="Extrato completo"
223→              title="Pontos disponíveis"
224→              valuePoints={formatPoints(points ?? 0)}
225→            />
226→
227→            <Text type="paragraphXXXL" mb="xxxs">
228→              Onde usar meus pontos
229→            </Text>
230→
231→            <CardMiddle
232→              items={MOCK_ITEMS as PropsCardMiddle['items']}
233→              renderType="grid"
234→              isLoading={isLoading}
235→              mb="xs"
236→            />
237→
238→            <LearnMoreSection isLoading={isLoading} />
239→          </Box>
240→        )}
241→      </ScrollView>
242→    </Box>
243→  );
244→}
245→
246→const meta: Meta<typeof PointsStoryWrapper> = {
247→  title: 'Screens/Points',
248→  component: PointsStoryWrapper,
249→  decorators: [NavigationDecorator],
250→  argTypes: {
